40	  try { localStorage.setItem("theme", dark ? "dark" : "light"); } catch (e) { /* ignore */ }
41	  const btn = document.getElementById("theme-toggle");
42	  if (btn) btn.textContent = dark ? "☀ Light" : "🌙 Dark";
