61	async function api(path, options) {
62	  _progress(1);
63	  try {
64	    const hasBody = options && options.body;
65	    // Only set Content-Type when there's a body, and never on FormData (which
66	    // needs the browser to set the multipart boundary itself).
67	    const headers = hasBody && !(options.body instanceof FormData)
68	      ? { "Content-Type": "application/json" } : {};
69	    const res = await fetch("/api" + path, { ...options, headers: { ...headers, ...(options && options.headers) } });
70	    let body = null;
71	    if (res.status !== 204) {
72	      try { body = await res.json(); }
73	      catch (_) { /* non-JSON error page (HTML 5xx, gateway, etc.) */ }
74	    }
75	    if (!res.ok) {
76	      const detail = body && body.detail !== undefined ? body.detail : res.statusText;
77	      throw new Error(_humanizeDetail(detail, `${res.status} ${res.statusText}`.trim()));
78	    }
79	    return body;
80	  } finally {
81	    _progress(-1);
82	  }
83	}
84	function toast(text, ok = true) {
85	  const box = document.getElementById("toasts");
86	  if (!box || !text) return;
87	  const t = document.createElement("div");
88	  t.className = "toast " + (ok ? "ok" : "bad");
89	  t.setAttribute("role", ok ? "status" : "alert");
90	  t.textContent = text;
91	  box.appendChild(t);
92	  setTimeout(() => { t.style.transition = "opacity .3s"; t.style.opacity = "0"; setTimeout(() => t.remove(), 300); }, ok ? 2500 : 5000);
93	}
94	function setMsg(id, text, ok) {
95	  const el = document.getElementById(id);
96	  if (el) {
97	    el.textContent = text;
