106	// Find the form input most likely responsible for a server error message and
107	// flag it (aria-invalid + .field-error + focus). Errors that don't match any
108	// field name fall back to the form-level message only.
109	function markInvalid(form, errorText) {
110	  if (!form || !errorText) return;
111	  // Strip prior invalid marks before re-evaluating.
112	  for (const el of form.querySelectorAll("[aria-invalid='true']")) {
113	    el.removeAttribute("aria-invalid"); el.classList.remove("field-error");
114	  }
115	  const t = String(errorText).toLowerCase();
116	  // candidates: input/select/textarea with a name
117	  const fields = [...form.elements].filter((e) => e.name);
118	  // word-boundary search: the field name (or its dash/space variants) appears in the error
119	  const hit = fields.find((e) => {
120	    const n = e.name.toLowerCase();
121	    const words = [n, n.replace(/_/g, " "), n.replace(/_/g, "-")];
122	    return words.some((w) => new RegExp("\\b" + w.replace(/[.*+?^${}()|[\]\\]/g, "\\$&") + "\\b").test(t));
123	  });
124	  if (hit) {
125	    hit.setAttribute("aria-invalid", "true"); hit.classList.add("field-error");
126	    try { hit.focus(); } catch (_) {}
127	  }
128	}
129	// Clear the invalid mark as soon as the user starts editing the flagged field.
130	document.addEventListener("input", (e) => {
131	  const t = e.target;
132	  if (t && t.getAttribute && t.getAttribute("aria-invalid") === "true") {
133	    t.removeAttribute("aria-invalid"); t.classList.remove("field-error");
134	  }
135	}, true);
