137	// Styled confirm dialog (replaces native confirm); returns a Promise<bool>.
138	function confirmDialog(message, okLabel = "Delete", okKind = "danger") {
139	  return new Promise((resolve) => {
140	    const m = document.getElementById("confirm-modal");
141	    const ok = document.getElementById("confirm-ok");
142	    const cancel = document.getElementById("confirm-cancel");
143	    document.getElementById("confirm-text").textContent = message;
144	    ok.textContent = okLabel;
145	    // Audit P41: reset class state every open so a previous "danger" label
146	    // doesn't leak into a benign confirm (e.g. order cancellation).
147	    ok.className = "confirm-ok " + (okKind === "danger" ? "danger" : "primary");
148	    m.hidden = false;
149	    ok.focus();
150	    const done = (v) => {
151	      m.hidden = true;
152	      ok.removeEventListener("click", onOk);
153	      cancel.removeEventListener("click", onCancel);
154	      document.removeEventListener("keydown", onKey);
155	      resolve(v);
156	    };
157	    const onOk = () => done(true);
158	    const onCancel = () => done(false);
159	    const onKey = (e) => { if (e.key === "Escape") done(false); else if (e.key === "Enter") done(true); };
160	    ok.addEventListener("click", onOk);
161	    cancel.addEventListener("click", onCancel);
162	    document.addEventListener("keydown", onKey);
163	  });
164	}
