170	function showShortcuts() {
171	  let m = document.getElementById("shortcuts-modal");
172	  if (!m) {
173	    m = document.createElement("div"); m.id = "shortcuts-modal"; m.className = "modal";
174	    m.innerHTML = `
175	      <div class="modal-box" role="dialog" aria-modal="true" aria-labelledby="shortcuts-title">
176	        <h3 id="shortcuts-title" style="margin-top:0">Keyboard shortcuts</h3>
177	        <table class="shortcuts"><tbody>
178	          <tr><th><kbd>/</kbd></th><td>Focus the page filter</td></tr>
179	          <tr><th><kbd>n</kbd></th><td>Add a new record on the active panel</td></tr>
180	          <tr><th><kbd>1</kbd>-<kbd>9</kbd></th><td>Jump to the Nth tab in the current menu</td></tr>
181	          <tr><th><kbd>Esc</kbd></th><td>Close the open dialog</td></tr>
182	          <tr><th><kbd>?</kbd></th><td>Show this help</td></tr>
183	        </tbody></table>
184	        <div class="actions-row" style="margin-top:0.75rem"><button type="button" id="shortcuts-close">Close</button></div>
185	      </div>`;
186	    document.body.appendChild(m);
187	    const close = () => { m.hidden = true; };
188	    m.querySelector("#shortcuts-close").addEventListener("click", close);
189	    m.addEventListener("click", (e) => { if (e.target === m) close(); });
190	  }
191	  m.hidden = false;
192	  requestAnimationFrame(() => m.querySelector("#shortcuts-close").focus());
193	}
