717	const GRIDS = {};  // panelId -> Tabulator (redrawn when its tab becomes visible)
718	// Audit M24: one place that redraws every Tabulator inside a panel when its
719	// tab becomes visible. Called from the tab-click handler + anywhere else that
720	// reveals a previously-hidden grid (e.g. player history sub-panel).
721	function _redrawPanelGrids(panelId) {
722	  const grids = GRIDS[panelId];
723	  if (!grids) return;
724	  requestAnimationFrame(() => grids.forEach((g) => { try { g.redraw(true); } catch (_) {} }));
725	}
726	// Audit M12: shared "deferred setData" pattern — Tabulator can't accept data
727	// until `tableBuilt` fires; without this helper every grid factory carried
728	// its own `built / pending` pair. Returns a function callers use in place of
729	// table.setData() directly.
730	function deferredSetData(table) {
731	  const state = { built: false, pending: null };
732	  table.on("tableBuilt", () => {
733	    state.built = true;
734	    if (state.pending !== null) { table.setData(state.pending); state.pending = null; }
735	  });
736	  const fn = (rows) => { if (state.built) table.setData(rows); else state.pending = rows; };
737	  fn._state = state;  // makeListGrid uses .built directly to gate filter installs
738	  return fn;
739	}
740	// Audit A48: an IntersectionObserver also catches *any* panel that becomes
741	// visible (history sub-panels, modals revealing a grid, etc.) without each
742	// caller having to wire up its own redraw. The Tabulator grids inside that
743	// panel can't lay out columns while their container is `display:none`.
744	const _panelObserver = new IntersectionObserver((entries) => {
745	  for (const e of entries) {
746	    if (e.isIntersecting && e.target.id) _redrawPanelGrids(e.target.id);
747	  }
748	}, { threshold: 0 });
749	function _observePanel(el) { if (el) _panelObserver.observe(el); }
750	// Walk the DOM after init wires panels.
751	requestAnimationFrame(() => {
752	  document.querySelectorAll(".panel").forEach(_observePanel);
753	});
